USE career_intelligence;

-- Skill_Taxonomy (hierarchy nodes)

-- Skills (canonical master list, deduped)

-- Skill_Alias (alternate surface forms -> canonical skill)
-- We resolve the canonical_id to Skills.id after insert using a subquery.

-- Link each Skill to its Skill_Taxonomy node (first match)
UPDATE Skills s
  JOIN Skill_Taxonomy st
    ON st.skill_id = s.canonical_id AND st.node_type = 'skill'
  SET s.taxonomy_id = st.id;
